codeunit 50100 A
{
    procedure MaxCtx(var Cust: Record Customer; flag: Boolean)
    var
        i: Integer;
    begin
        Cust.FindSet();
        if flag then begin
            Cust.Modify();
            for i := 1 to 10 do
                Cust.Delete();
        end;
    end;
}

codeunit 50100 B
{
    procedure Branches(var Cust: Record Customer; i: Integer)
    begin
        if Cust.IsEmpty() then
            Cust.Init()
        else
            Cust.Modify();
        case i of
            1:
                Cust.Insert();
            else
                Cust.Delete();
        end;
    end;
}

codeunit 50100 C
{
    procedure Guard(var Cust: Record Customer; bad: Boolean)
    begin
        if bad then
            Error('boom');
        Cust.Modify();
    end;
}

codeunit 50100 D1
{
    procedure BareError(var Cust: Record Customer)
    begin
        Error('always');
        Cust.Modify();
        Commit();
    end;
}

codeunit 50100 D2
{
    procedure BothExit(var Cust: Record Customer; flag: Boolean)
    begin
        if flag then
            exit
        else
            exit;
        Cust.Modify();
    end;
}

codeunit 50100 D3
{
    procedure CaseTerm(var Cust: Record Customer; i: Integer)
    begin
        case i of
            1:
                exit;
            2:
                Cust.Insert();
        end;
        Cust.Modify();
    end;
}

codeunit 50100 E1
{
    procedure PosGuard(var IsHandled: Boolean; var Cust: Record Customer)
    begin
        if IsHandled then
            exit;
        Cust.Modify();
    end;
}

codeunit 50100 E2
{
    procedure NegGuard(var IsHandled: Boolean; var Cust: Record Customer)
    begin
        if not IsHandled then
            Cust.Modify();
    end;
}

codeunit 50100 E3
{
    procedure FalseGuard(var IsHandled: Boolean; var Cust: Record Customer)
    begin
        if IsHandled = false then
            Cust.Modify();
    end;
}

codeunit 50100 E4
{
    procedure PubGuard(var Cust: Record Customer)
    var
        Handled: Boolean;
    begin
        OnBefore(Handled);
        if Handled then
            exit;
        Cust.Modify();
    end;

    procedure OnBefore(var h: Boolean)
    begin
    end;
}

codeunit 50100 E5
{
    procedure NegIneligible(flag: Boolean; var Cust: Record Customer)
    begin
        if not flag then
            Cust.Modify();
    end;
}

codeunit 50100 F
{
    [TryFunction]
    procedure TryIt(var Cust: Record Customer)
    begin
        Cust.FindSet();
        if Cust.IsEmpty() then
            Cust.Modify();
        Commit();
    end;
}

codeunit 50100 G
{
    procedure ErrInLoop(var Cust: Record Customer; i: Integer)
    begin
        while i < 10 do
            Error('in loop');
    end;
}
